Here's the XAML and ViewModel setup:

**XAML**

```xml
<RefreshView IsRefreshing="{Binding IsRefreshing}"
             Command="{Binding RefreshCommand}">
    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding CurrentItem, Mode=TwoWay}"
                    SelectionChangedCommand="{Binding ItemSelectedCommand}">
        <CollectionView.ItemTemplate>
            <DataTemplate x:DataType="models:Item">
                <Grid Padding="12" ColumnDefinitions="Auto,*">
                    <Image Source="{Binding Icon}" WidthRequest="40" HeightRequest="40" />
                    <Label Grid.Column="1" Text="{Binding Name}" VerticalOptions="Center" />
                </Grid>
            </DataTemplate>
        </CollectionView.ItemTemplate>
        <CollectionView.EmptyView>
            <ContentView>
                <Label Text="No items found." HorizontalOptions="Center" VerticalOptions="Center" />
            </ContentView>
        </CollectionView.EmptyView>
    </CollectionView>
</RefreshView>
```

**ViewModel**

```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;
    private readonly INavigationService _nav;

    [ObservableProperty]
    private Item? currentItem;

    [ObservableProperty]
    private bool isRefreshing;

    public ObservableCollection<Item> Items { get; } = new();

    [RelayCommand]
    private async Task ItemSelected()
    {
        if (CurrentItem is null) return;

        await _nav.GoToAsync(nameof(DetailPage), new Dictionary<string, object>
        {
            { "Item", CurrentItem }
        });

        // Clear selection so the same item can be re-selected later
        CurrentItem = null;
    }

    [RelayCommand]
    private async Task Refresh()
    {
        try
        {
            var data = await _api.GetItemsAsync();
            MainThread.BeginInvokeOnMainThread(() =>
            {
                Items.Clear();
                foreach (var item in data)
                    Items.Add(item);
            });
        }
        finally
        {
            IsRefreshing = false;   // Must set false to dismiss the spinner
        }
    }
}
```

**Key bindings explained:**

| XAML Property | ViewModel Property | Purpose |
|---|---|---|
| `IsRefreshing` | `IsRefreshing` (bool, TwoWay) | Shows/hides the refresh spinner |
| `Command` (RefreshView) | `RefreshCommand` | Triggers API reload; **must set `IsRefreshing = false`** when done |
| `SelectedItem` | `CurrentItem` (TwoWay) | Tracks the selected item; null it after navigation |
| `SelectionChangedCommand` | `ItemSelectedCommand` | Fires on selection — navigates to detail page |
| `ItemsSource` | `Items` (ObservableCollection) | **Must be `ObservableCollection<T>`**, not `List<T>`, so the UI updates on add/remove |

**Important rules:**
- Never use `ViewCell` in the template — use `Grid`, `StackLayout`, or any `View`.
- Set `x:DataType` on `DataTemplate` for compiled bindings.
- Always update the collection on the **UI thread** (`MainThread.BeginInvokeOnMainThread`).
- Reset `CurrentItem = null` after navigating so the same item can be tapped again.
